def find_zero(xs: list):
    from scipy.optimize import fsolve

    def func(x):
        return poly(xs, x)

    initial_guess = 0
    zero = fsolve(func, initial_guess)[0]
    return zero
```

```python
def find_zero(xs: list):
    from scipy.optimize import fsolve

    def func(x):
        return poly(xs, x)

    initial_guess = 0.0
    zero_point = fsolve(func, initial_guess)
    return zero_point[0]
```

